function check(){for(var e=document.getElementById("checbox"),c=document.getElementsByClassName("price1"),l=document.getElementsByClassName("price2"),t=0;t<c.length;t++)1==e.checked?(c[t].style.display="block",l[t].style.display="none"):0==e.checked&&(c[t].style.display="none",l[t].style.display="block")}check();